def min_max(numbers):
    """Return both the minimum and maximum of a list."""
    return min(numbers), max(numbers)

lowest, highest = min_max([4, 1, 8, 2, 9])
print(f"Min: {lowest}")
print(f"Max: {highest}")

def total(*args):
    """Sum all provided numbers."""
    print(f"Received: {args}")
    return sum(args)

print(total(1, 2, 3))
print(total(10, 20, 30, 40, 50))

def build_profile(name, kwargs):
    """Build a user profile dictionary."""
    profile = {"name": name}
    profile.update(kwargs)
    return profile

result = build_profile("Alice", age=30, city="NYC", role="Developer")
for key, value in sorted(result.items()):
    print(f"{key}: {value}")

