operations = {
    "add": lambda a, b: a + b,
    "sub": lambda a, b: a - b,
    "mul": lambda a, b: a * b,
}

def calculate(op_name, a, b):
    if op_name in operations:
        return operations[op_name](a, b)
    return "Unknown operation"

print(calculate("add", 10, 5))
print(calculate("sub", 10, 5))
print(calculate("mul", 10, 5))
print(calculate("div", 10, 5))

import random

def make_retry(func, max_attempts):
    def wrapper():
        last_error = None
        for attempt in range(max_attempts):
            try:
                return func()
            except Exception as e:
                last_error = e
        print(f"All {max_attempts} attempts failed: {last_error}")
        return None
    return wrapper

call_count = 0

def flaky_function():
    global call_count
    call_count += 1
    if call_count < 3:
        raise ValueError(f"Attempt {call_count} failed")
    return f"Success on attempt {call_count}"

random.seed(42)
safe_call = make_retry(flaky_function, 5)
print(safe_call())
